if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const plan_id = $('Build Context').item.json.plan_id;
const existing = $('Build Context').item.json.existing_plan_data || {};
const resp = $input.first().json || {};

let text = '';
try { if (resp.content && resp.content[0]) text = resp.content[0].text || ''; } catch(e) {}

let enriched = {};
try {
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start !== -1 && end !== -1) enriched = JSON.parse(text.substring(start, end + 1));
} catch(e) { enriched = {_parse_error: e.message, _raw: text.slice(0,300)}; }

const merged = Object.assign({}, existing, enriched, {
  enriched_at: new Date().toISOString(),
  enriched_by: 'gda-enrich-capture-plans',
  enriched_via: 'Claude Sonnet 4 + Tavily + GDA OppTracker'
});

return [{json: {plan_id: plan_id, merged_plan_data: merged, enrichment_status: enriched._parse_error ? 'PARSE_ERROR' : 'SUCCESS'}}];
